import { ChangeDetectionStrategy, Component, computed, inject, input, model, output, signal } from '@angular/core';
import { Router, ActivatedRoute } from '@angular/router';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';
import { DataGridComponent, GridPageTitleComponent, ConfirmationDialogService } from '@nxgn-solutions/ui';
import { type ColDef, type RowDoubleClickedEvent } from 'ag-grid-community';

import { ActionEvidenceDTO } from './action.models';

@Component({
  selector: 'app-action-evidence-list',
  standalone: true,
  imports: [DataGridComponent, GridPageTitleComponent, TranslatePipe],
  template: `
    <nxgn-grid-page-title
      [title]="'actions.evidence.title' | translate"
      [showAdd]="!disabled()"
      [showDelete]="!disabled()"
      [selectedItems]="selectedItems()"
      (add)="onAdd()"
      (edit)="onEdit()"
      (delete)="onDelete()"
    >
      <!-- Domain command buttons go in the custom-buttons slot -->
      <ng-container custom-buttons>
        <button
          type="button"
          class="btn btn-sm btn-outline-secondary"
          [disabled]="!canMarkReviewed()"
          (click)="onMarkReviewed()"
        >
          {{ reviewStatusLabel() | translate }}
        </button>
      </ng-container>
    </nxgn-grid-page-title>
    <nxgn-data-grid
      [columnDefs]="columnDefs"
      [dataItems]="evidence()"
      [multiSelect]="true"
      (rowDoubleClicked)="onRowDoubleClicked($event)"
      (selectionChanged)="onSelectionChanged($event)"
    />
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ActionEvidenceListComponent {
  private readonly router = inject(Router);
  private readonly route = inject(ActivatedRoute);
  private readonly confirmService = inject(ConfirmationDialogService);

  // --- Data binding ---
  /** Two-way bound child array from parent capture component */
  evidence = model.required<ActionEvidenceDTO[]>();

  // --- Configuration inputs ---
  /** Disable CRUD actions (e.g., system apps) */
  disabled = input(false);
  /** Whether to show domain command actions (only in edit mode with saved records) */
  showActions = input(false);

  // --- Domain command outputs (parent handles the API call) ---
  markReviewed = output<ActionEvidenceDTO>();

  // --- Local state ---
  selectedItems = signal<{ id: string }[]>([]);

  canMarkReviewed = computed(() => this.showActions() && this.selectedItems().length > 0);

  reviewStatusLabel = computed(() => {
    const selectedIds = new Set(this.selectedItems().map(s => s.id));
    const selected = this.evidence().filter(c => selectedIds.has(c.id));
    if (selected.length > 0 && selected.every(c => c.status.name === 'Approved')) return 'actions.evidence.reject';
    if (selected.length > 0 && selected.every(c => c.status.name === 'Rejected')) return 'actions.evidence.approve';
    return 'actions.evidence.reject';
  });

  // --- Column definitions ---
  columnDefs: ColDef<ActionEvidenceDTO>[] = [
    { field: 'fileName', headerName: 'File Name', flex: 1.5 },
    { field: 'description', headerName: 'Description', flex: 2 },
    {
      field: 'evidenceType',
      headerName: 'Type',
      flex: 0.8,
      valueFormatter: (params) => params.value?.name ?? '',
    },
    {
      field: 'status',
      headerName: 'Status',
      flex: 0.8,
      valueFormatter: (params) => params.value?.name ?? '',
    },
    {
      field: 'uploadedDate',
      headerName: 'Uploaded',
      flex: 1,
      valueFormatter: (params) =>
        params.value ? new Date(params.value).toLocaleDateString() : '',
    },
  ];

  // --- Navigation (child routes, not modals) ---
  onAdd(): void {
    this.router.navigate(['evidence', 'new'], { relativeTo: this.route });
  }

  onEdit(): void {
    const selected = this.selectedItems();
    if (selected.length === 1) {
      this.router.navigate(['evidence', selected[0].id], { relativeTo: this.route });
    }
  }

  onRowDoubleClicked(event: RowDoubleClickedEvent<ActionEvidenceDTO>): void {
    if (this.disabled() || !event.data) return;
    this.router.navigate(['evidence', event.data.id], { relativeTo: this.route });
  }

  // --- Local mutations (modify model in place, saved with parent) ---
  async onDelete(): Promise<void> {
    const selectedIds = new Set(this.selectedItems().map(s => s.id));
    if (selectedIds.size === 0) return;

    const confirmed = await this.confirmService.confirmDelete(
      await firstValueFrom(this.translate.get('actions.evidence.deleteTitle')),
      await firstValueFrom(this.translate.get('actions.evidence.deleteMessage', { count: selectedIds.size })),
    );
    if (!confirmed) return;

    this.evidence.update(list => list.filter(c => !selectedIds.has(c.id)));
    this.selectedItems.set([]);
  }

  // --- Domain command delegation ---
  onMarkReviewed(): void {
    const selectedIds = new Set(this.selectedItems().map(s => s.id));
    const selected = this.evidence().filter(c => selectedIds.has(c.id));
    for (const evidence of selected) {
      this.markReviewed.emit(evidence);
    }
  }

  // --- Grid selection tracking ---
  onSelectionChanged(rows: ActionEvidenceDTO[]): void {
    this.selectedItems.set(rows.map(r => ({ id: r.id })));
  }
}

