/** Track IDs loaded from the server to distinguish new vs existing items */
private serverEvidenceIds = new Set<string>();
private serverConsultationIds = new Set<string>();

// On load: populate state and record server IDs
private async loadAction(id: string): Promise<void> {
  const actionData = await this.actionService.get(id);
  this.evidence.set(actionData.evidence);
  this.consultations.set(actionData.consultations);
  this.serverEvidenceIds = new Set(actionData.evidence.map(c => c.id));
  this.serverConsultationIds = new Set(actionData.consultations.map(c => c.id));
}

// On save: map temp UUIDs back to EMPTY_GUID for new items
async onSave(): Promise<void> {
  const evidence = this.evidence().map(c => ({
    ...c,
    id: this.serverEvidenceIds.has(c.id) ? c.id : EMPTY_GUID,
  }));
  const consultations = this.consultations().map(c => ({
    ...c,
    id: this.serverConsultationIds.has(c.id) ? c.id : EMPTY_GUID,
  }));

  const request: SaveActionRequest = {
    id: this.isEditMode() ? this.id()! : EMPTY_GUID,
    name: this.name().trim(),
    slug: this.slug().trim(),
    evidence,
    consultations,
  };

  const result = await this.actionService.save(request);
