}

// Domain command handler: call API, reload entity
async onToggleEvidenceStatus(evidence: ActionEvidenceDTO): Promise<void> {
  const isApproved = evidence.status.name === 'Approved';
  const confirmed = await this.confirmService.confirm(
    await firstValueFrom(this.translate.get(
      isApproved ? 'actions.evidence.rejectConfirm' : 'actions.evidence.approveConfirm',
      { name: evidence.fileName },
    )),
    await firstValueFrom(this.translate.get('actions.evidence.statusTitle')),
    {
      variant: isApproved ? 'danger' : 'primary',
      confirmLabel: await firstValueFrom(this.translate.get(
        isApproved ? 'common.reject' : 'common.approve',
      )),
    },
  );
  if (!confirmed) return;

  const newStatus: EnumDTO = isApproved
    ? { id: 2, name: 'Rejected' }
    : { id: 1, name: 'Approved' };
  await this.actionService.setEvidenceStatus(this.action()!.id, evidence.id, { status: newStatus });
  await this.loadAction(this.action()!.id);  // Reload to reflect server state
}

